function solve(nums) {
    /**
     * Checks if array A is a cyclic permutation of array B.
     * This means A can be obtained by rotating B.
     * Assumes A and B have the same length k.
     * @param {number[]} A The potential rotated array (Target)
     * @param {number[]} B The original array (Source)
     * @returns {boolean} True if A is a cyclic permutation of B.
     */
    const isCyclicPermutation = (A, B) => {
        const k = A.length;
        if (k === 0) return true;

        // Concatenate B with itself (B_double)
        const B_double = B.concat(B);

        // Check all k possible starting points (rotations) in B_double
        for (let start = 0; start < k; start++) {
            let match = true;
            for (let i = 0; i < k; i++) {
                // Compare A[i] with the element in B_double starting at 'start'
                if (A[i] !== B_double[start + i]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                return true;
            }
        }

        return false;
    };

    const n = nums.length;
    if (n === 0) return 0;

    // 1. Sort the original array to get the target array S
    const S = [...nums].sort((a, b) => a - b);

    // 2. Find all divisors k of n
    const divisors = [];
    for (let k = 1; k * k <= n; k++) {
        if (n % k === 0) {
            divisors.push(k);
            if (k * k !== n) {
                divisors.push(n / k);
            }
        }
    }

    let totalSum = 0;

    // 3. Check each divisor k
    for (const k of divisors) {
        let isSortable = true;

        const m = n / k; // Number of blocks

        for (let i = 0; i < m; i++) {
            const startIdx = i * k;

            // Extract blocks B_i (from nums) and S_i (from S)
            const B_i = nums.slice(startIdx, startIdx + k);
            const S_i = S.slice(startIdx, startIdx + k);

            // We need to check if S_i can be obtained by cyclically shifting B_i.
            // i.e., S_i must be a cyclic permutation of B_i.
            if (!isCyclicPermutation(S_i, B_i)) {
                isSortable = false;
                break;
            }
        }

        if (isSortable) {
            totalSum += k;
        }
    }

    return totalSum;
}

